sql:
SELECT AVG(pts) AS average_points
FROM player_statistics
WHERE season = 2022;

external_knowledge:
- "shining beacons of victory" metaphorically refers to the top-performing teams;
- "ascended to the pinnacle of glory" metaphorically represents the teams that are ranked the highest;
- "luminous winning percentages and radiant points scored" metaphorically describes high win percentages and high points scored, respectively.

- 'recent overall performance' refers to the last three seasons;
- 'win rate' is represented by the average win percentage;
- 'scoring efficiency' is represented by the total points scored over the period.

sql:
SELECT SUM(pts) AS total_points
FROM player_statistics
WHERE season = 2013;
